import React, { useState } from 'react';
import './assets/styles/global.css';

function App() {
  const [showAssistant, setShowAssistant] = useState(false);

  const stats = [
    { label: 'Km idag', value: '124', icon: '🧭' },
    { label: 'Körtid', value: '2h 15m', icon: '⚡' },
    { label: 'Stopp', value: '3', icon: '📍' },
  ];

  return (
    <div style={{ backgroundColor: '#F5F2ED', minHeight: '100vh', padding: '20px', fontFamily: 'sans-serif', color: '#2D3436', position: 'relative', overflow: 'hidden' }}>

      {/* Header */}
      <header style={{ marginBottom: '30px' }}>
        <h1 style={{ fontSize: '24px', fontWeight: 'bold', color: '#2D5A27' }}>Hej Buddy! 🚐</h1>
        <p style={{ color: '#636E72' }}>Solen går ner om 3 timmar. Letar vi nattplats?</p>
      </header>

      {/* Stats-sektionen */}
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: '10px', marginBottom: '30px' }}>
        {stats.map((stat, i) => (
          <div key={i} style={{ backgroundColor: '#FFF', padding: '15px', borderRadius: '15px', textAlign: 'center', boxShadow: '0 2px 5px rgba(0,0,0,0.05)' }}>
            <div style={{ fontSize: '24px', marginBottom: '5px' }}>{stat.icon}</div>
            <div style={{ fontSize: '18px', fontWeight: 'bold' }}>{stat.value}</div>
            <div style={{ fontSize: '10px', color: '#95A5A6', textTransform: 'uppercase' }}>{stat.label}</div>
          </div>
        ))}
      </div>

      {/* Vanliga menyvalen */}
      <section>
        <h2 style={{ fontSize: '18px', marginBottom: '15px' }}>Vad vill du göra nu?</h2>
        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '15px' }}>
          <button style={actionButtonStyle}>
            <span style={{ fontSize: '24px', marginBottom: '8px' }}>📸</span>
            <span>Fota & Logga</span>
          </button>
          <button style={actionButtonStyle}>
            <span style={{ fontSize: '24px', marginBottom: '8px' }}>🫂</span>
            <span>Min Konvoj</span>
          </button>
        </div>
      </section>

      {/* UTVECKLARKNAPP */}
      <button 
        onClick={() => setShowAssistant(true)}
        style={{ position: 'fixed', bottom: '20px', right: '20px', backgroundColor: '#D35400', color: 'white', border: 'none', padding: '15px', borderRadius: '50px', fontWeight: 'bold', cursor: 'pointer', boxShadow: '0 4px 10px rgba(0,0,0,0.2)', zIndex: 10 }}>
        🛑 Simulera Stopp
      </button>

      {/* --- PREMIUM-ANIMERAD ASSISTENT --- */}
      {/* Bakgrunds-dimmern */}
      <div style={{
        ...overlayStyle,
        opacity: showAssistant ? 1 : 0,
        pointerEvents: showAssistant ? 'auto' : 'none'
      }}>
        {/* Själva menyn som glider upp och ner */}
        <div style={{
          ...bottomSheetStyle,
          transform: showAssistant ? 'translateY(0)' : 'translateY(100%)'
        }}>
          <h2 style={{ fontSize: '22px', color: '#2D5A27', marginBottom: '5px', marginTop: '0' }}>Härlig plats! 🌲</h2>
          <p style={{ color: '#636E72', marginBottom: '25px', lineHeight: '1.5' }}>
            Jag känner att vi har stannat. Det är 18°C och soligt just nu. Vill du spara platsen i loggboken?
          </p>

          <div style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
            <button style={primaryBtnStyle}>☀️ Logga väder & plats</button>
            <button style={secondaryBtnStyle}>📸 Lägg till ett foto</button>
            <button style={secondaryBtnStyle}>🗺️ Dela med Konvojen</button>
          </div>

          <button 
            onClick={() => setShowAssistant(false)} 
            style={cancelBtnStyle}>
            Nej, vi ska bara sträcka på benen (Avbryt)
          </button>
        </div>
      </div>

    </div>
  );
}

// --- DESIGNMALLAR (STYLES) ---

const actionButtonStyle = {
  backgroundColor: '#2D5A27', color: 'white', border: 'none', padding: '20px', borderRadius: '20px', display: 'flex', flexDirection: 'column', alignItems: 'center', fontSize: '14px', fontWeight: '600', cursor: 'pointer'
};

const overlayStyle = {
  position: 'fixed', top: 0, left: 0, right: 0, bottom: 0, 
  backgroundColor: 'rgba(0,0,0,0.6)', 
  display: 'flex', flexDirection: 'column', justifyContent: 'flex-end', 
  zIndex: 1000,
  transition: 'opacity 0.3s ease-out' /* Mjuk övergång för dimmern */
};

const bottomSheetStyle = {
  backgroundColor: '#FFF', padding: '30px 20px', 
  borderTopLeftRadius: '30px', borderTopRightRadius: '30px', 
  boxShadow: '0 -5px 20px rgba(0,0,0,0.1)',
  transition: 'transform 0.4s cubic-bezier(0.16, 1, 0.3, 1)' /* Mjuk premium-glidning in och ut */
};

const primaryBtnStyle = {
  backgroundColor: '#2D5A27', color: 'white', border: 'none', padding: '16px', borderRadius: '15px', fontSize: '16px', fontWeight: 'bold', cursor: 'pointer'
};

const secondaryBtnStyle = {
  backgroundColor: '#F5F2ED', color: '#2D3436', border: 'none', padding: '16px', borderRadius: '15px', fontSize: '16px', fontWeight: '600', cursor: 'pointer'
};

const cancelBtnStyle = {
  width: '100%', padding: '20px 0 10px 0', backgroundColor: 'transparent', border: 'none', color: '#95A5A6', fontWeight: 'bold', cursor: 'pointer', fontSize: '14px', marginTop: '10px'
};

export default App
